import React from "react";

export default function Footer() {
  const socialLinks = {
    facebook: "https://www.facebook.com/share/1K1tDP2Vew/?mibextid=wwXIfr",
    instagram: "https://www.instagram.com/yassin_abdelkader/",
    youtube: "https://www.youtube.com/",
    github: "https://www.github.com/"
  };

  const socialIcons = [
    {
      name: "facebook",
      icon: "fab fa-facebook-f",
      bgColor: "#1877f2",
      hoverBg: "#145dbf",
      link: socialLinks.facebook,
    },
    {
      name: "instagram",
      icon: "fab fa-instagram",
      bgColor: "linear-gradient(45deg, #f09433, #d62976, #962fbf)",
      hoverBg: "linear-gradient(45deg, #e0861e, #c21e66, #7a1fa0)",
      link: socialLinks.instagram,
    },
    {
      name: "youtube",
      icon: "fab fa-youtube",
      bgColor: "#ff0000",
      hoverBg: "#cc0000",
      link: socialLinks.youtube,
    },
    {
      name: "github",
      icon: "fab fa-github",
      bgColor: "#24292e",
      hoverBg: "#1a1e22",
      link: socialLinks.github,
    }
  ];

  const footerLinks = [
    { name: "À propos", href: "#about" },
    { name: "Blog", href: "#blog" },
    { name: "Services", href: "#services" },
    { name: "Projets", href: "#projects" },
    { name: "Contact", href: "#contact" }
  ];

  // Styles personnalisés pour les icônes Instagram (car dégradé)
  const getIconStyle = (social) => {
    if (social.name === "instagram") {
      return {
        background: social.bgColor,
        transition: "all 0.3s ease-out"
      };
    }
    return {
      backgroundColor: social.bgColor,
      transition: "all 0.3s ease-out"
    };
  };

  const getHoverStyle = (social) => {
    if (social.name === "instagram") {
      return {
        background: social.hoverBg
      };
    }
    return {
      backgroundColor: social.hoverBg
    };
  };

  return (
    <>
      <footer className="relative bg-gradient-to-br from-gray-50 to-gray-100 pt-8 pb-6 border-t border-gray-200">
        {/* SVG Wave Decoration */}
        <div
          className="bottom-auto top-0 left-0 right-0 w-full absolute pointer-events-none overflow-hidden -mt-20 h-20"
          style={{ transform: "translateZ(0)" }}
        >
          <svg
            className="absolute bottom-0 overflow-hidden"
            xmlns="http://www.w3.org/2000/svg"
            preserveAspectRatio="none"
            version="1.1"
            viewBox="0 0 2560 100"
            x="0"
            y="0"
          >
            <polygon
              className="text-gray-50 fill-current"
              points="2560 0 2560 100 0 100"
            ></polygon>
          </svg>
        </div>

        <div className="container mx-auto px-4 relative">
          {/* Tout le contenu centré */}
          <div className="flex flex-col items-center justify-center text-center">

            {/* Liens utiles - étalés sur toute la largeur */}
            <div className="w-full mb-12">
              <span className="block uppercase text-gray-500 text-xs font-semibold mb-6 tracking-wider">
                Liens utiles
              </span>
              <div className="flex justify-between items-center w-full gap-4 flex-wrap">
                {footerLinks.map((link, index) => (
                  <a
                    key={index}
                    className="text-gray-600 hover:text-gray-900 font-medium text-sm transition-all duration-300 hover:translate-y-[-2px] inline-flex items-center gap-2 group flex-1 text-center justify-center"
                    href={link.href}
                  >
                    <i className="fas fa-chevron-right text-xs group-hover:translate-x-1 transition-transform"></i>
                    {link.name}
                  </a>
                ))}
              </div>
            </div>

            {/* Séparateur principal */}
            <div className="w-full">
              <hr className="my-8 border-gray-300" />
            </div>

            {/* Section des icônes sociales avec couleurs fixes */}
            <div className="w-full">
              <h4 className="text-2xl font-bold bg-gradient-to-r from-gray-800 to-gray-600 bg-clip-text text-transparent mb-3">
                Restons en contact !
              </h4>
              <p className="text-md text-gray-600 mb-8">
                Retrouvez-nous sur ces plateformes
              </p>

              {/* Social Icons avec couleurs personnalisées */}
              <div className="flex justify-between items-center w-full gap-4 flex-wrap">
                {socialIcons.map((social) => (
                  <button
                    key={social.name}
                    className="font-normal h-14 w-14 items-center justify-center align-center rounded-2xl outline-none focus:outline-none hover:scale-110 hover:shadow-2xl transition-all duration-300 ease-out border-0 group relative overflow-hidden flex-1 max-w-[80px] text-white"
                    style={getIconStyle(social)}
                    onMouseEnter={(e) => {
                      const btn = e.currentTarget;
                      if (social.name === "instagram") {
                        btn.style.background = social.hoverBg;
                      } else {
                        btn.style.backgroundColor = social.hoverBg;
                      }
                    }}
                    onMouseLeave={(e) => {
                      const btn = e.currentTarget;
                      if (social.name === "instagram") {
                        btn.style.background = social.bgColor;
                      } else {
                        btn.style.backgroundColor = social.bgColor;
                      }
                    }}
                    onClick={() => window.open(social.link, '_blank')}
                    aria-label={social.name}
                  >
                    <span className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300 bg-white/20"></span>
                    <i className={`${social.icon} text-2xl transition-transform duration-300 group-hover:scale-110`}></i>
                  </button>
                ))}
              </div>
            </div>

            {/* Séparateur */}
            <div className="w-full">
              <hr className="my-10 border-gray-300" />
            </div>

            {/* Copyright Section */}
            <div className="w-full">
              <div className="text-sm text-gray-500 font-medium">
                <i className="far fa-copyright"></i> {new Date().getFullYear()} Tous droits réservés | 
                Conçu avec <span className="inline-block mx-1">
                  <i className="fas fa-heart text-red-500 animate-pulse"></i>
                </span> par <span className="text-gray-700 font-semibold">Yassin Abdelkader</span>
              </div>
            </div>
          </div>
        </div>
      </footer>

      {/* Add Font Awesome Icons */}
      <link 
        rel="stylesheet" 
        href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css" 
      />
    </>
  );
}
